const body = $json.body || $json;
const payload = body.payload || body;
const search = payload.search || {};
const callback = payload.callback || body.callback || {};
return [{
  json: {
    tenant_id: payload.tenant_id || body.tenant_id,
    appointment_id: payload.appointment_id || payload.appointment?.id,
    request_id: payload.request_id || body.request_id || null,
    request_token: payload.request_token || callback.token || body.request_token || '',
    callback_url: callback.url || 'https://rsconnect.rsautomacaodigital.cloud/webhooks/calendar/availability',
    search_start_at: search.start_at,
    search_end_at: search.end_at,
    duration_minutes: search.duration_minutes || 50,
    timezone: search.timezone || 'America/Sao_Paulo',
    max_suggestions: search.max_suggestions || 5,
    appointment: payload.appointment || {},
    original: body
  }
}];

// Substitua este nó pela consulta real no Google Calendar / agenda externa.
// Ele gera horários de exemplo dentro da janela recebida para validar o fluxo.
const start = new Date($json.search_start_at || Date.now());
const duration = Number($json.duration_minutes || 50);
const max = Number($json.max_suggestions || 5);
const slots = [];
let cursor = new Date(start);
cursor.setHours(9, 0, 0, 0);
for (let i = 0; i < max; i++) {
  const s = new Date(cursor);
  s.setDate(s.getDate() + i);
  const e = new Date(s.getTime() + duration * 60000);
  slots.push({
    start: s.toISOString(),
    end: e.toISOString(),
    label: s.toLocaleString('pt-BR', { timeZone: $json.timezone || 'America/Sao_Paulo' })
  });
}
return [{ json: { ...$json, slots } }];

return [{
  json: {
    request_id: $json.request_id,
    request_token: $json.request_token,
    appointment_id: $json.appointment_id,
    source: 'n8n_google_calendar',
    slots: $json.slots || []
  }
}];
